import{_ as o,o as r,c as d,a3 as a}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"富文本渲染测试","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/rich-text-renderer.md","filePath":"user-guide/tools/rich-text-renderer.md","lastUpdated":1781934556000}'),e={name:"user-guide/tools/rich-text-renderer.md"};function l(i,t,n,s,h,c){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="富文本渲染测试" tabindex="-1">富文本渲染测试 <a class="header-anchor" href="#富文本渲染测试" aria-label="Permalink to &quot;富文本渲染测试&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>富文本渲染测试是一个专为 LLM（大语言模型）流式输出场景设计的<strong>富文本渲染引擎测试工具</strong>。它让你能够在可视化的环境中测试、调试和对比不同渲染器版本对 Markdown、HTML、数学公式、Mermaid 图表等内容的渲染效果，是开发智能体应用时的&quot;渲染实验室&quot;。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>四引擎对比测试</strong>：支持 V1（Markdown-it）、V2（自研 AST 解析器）、Pure Markdown-it、Hybrid V3 四种渲染器，一键切换对比</li><li><strong>流式输出模拟</strong>：模拟 LLM 打字机效果，支持自定义速度、延迟和波动模式，测试流式渲染的实时表现</li><li><strong>动态样式编辑</strong>：所见即所得地调整 Markdown 元素（标题、粗体、引用块等）的颜色、阴影、边框等 CSS 样式</li><li><strong>复杂内容覆盖</strong>：预设 24+ 个测试用例，覆盖代码块、表格、Mermaid 图表、KaTeX 公式、LLM 思考块、HTML 沙箱、VCP 工具调用等场景</li><li><strong>可视化 AST 调试</strong>：实时展示渲染引擎的抽象语法树（AST）结构，支持稳定区/待定区染色，辅助排查渲染问题</li></ul><div class="tip custom-block"><p class="custom-block-title">一句话总结</p><p>如果你需要确认一段 LLM 输出的 Markdown 内容在各种渲染模式下看起来什么样——这就是你要找的工具。</p></div><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次测试-5-步走" tabindex="-1">首次测试 5 步走 <a class="header-anchor" href="#首次测试-5-步走" aria-label="Permalink to &quot;首次测试 5 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>富文本渲染测试</strong>，点击进入。页面默认采用&quot;上输入 + 下预览&quot;的双栏布局。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注输入区、预览区、配置面板、预设列表</p></blockquote><p><strong>第二步：选择一个预设内容</strong></p><p>点击工具栏的 <strong>预设</strong> 下拉菜单，选择一个测试用例。建议从 <strong>基本测试 (basic)</strong> 开始——它包含了最常用的 Markdown 语法元素，适合快速验证基础渲染效果。</p><blockquote><p>TODO: 截图 - 预设下拉菜单展开，展示预设列表</p></blockquote><p><strong>第三步：查看渲染效果</strong></p><p>预设内容会自动填入输入区，右侧预览区会立即展示渲染后的效果。你可以看到：</p><ul><li>Markdown 语法被正确解析（标题、粗体、列表等）</li><li>代码块带有语法高亮</li><li>表格以规范的表格形式展示</li><li>链接可点击、图片可预览</li></ul><blockquote><p>TODO: 截图 - 基本测试的输入内容与渲染结果对比</p></blockquote><p><strong>第四步：切换渲染器版本</strong></p><p>在右侧的 <strong>渲染配置</strong> 区域，找到 <strong>渲染器版本</strong> 下拉菜单。试试从默认的 <strong>V2 - Custom Parser</strong> 切换到 <strong>V1 - Markdown-it</strong>，观察同一个内容在不同引擎下的渲染差异。</p><blockquote><p>TODO: 截图 - 渲染器版本切换下拉菜单</p></blockquote><p><strong>第五步：尝试流式模式</strong></p><p>在工具栏关闭 <strong>流式模式</strong> 开关（默认开启），然后点击 <strong>重新渲染</strong> 按钮。内容会以打字机效果逐字输出，模拟 LLM 的实时响应体验。</p><blockquote><p>TODO: 截图 - 流式模式开关位置标注</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="输入区" tabindex="-1">输入区 <a class="header-anchor" href="#输入区" aria-label="Permalink to &quot;输入区&quot;">​</a></h3><p>输入区位于页面顶部，用于输入或编辑待测试的 Markdown/HTML 内容。</p><h4 id="基本操作" tabindex="-1">基本操作 <a class="header-anchor" href="#基本操作" aria-label="Permalink to &quot;基本操作&quot;">​</a></h4><ul><li><strong>直接输入</strong>：在编辑器中直接输入 Markdown 文本，预览区会实时更新</li><li><strong>清空内容</strong>：点击工具栏的 <strong>清空</strong> 按钮重置输入</li><li><strong>从预设加载</strong>：从预设下拉菜单选择一个预设，内容自动填入</li></ul><h4 id="输入格式支持" tabindex="-1">输入格式支持 <a class="header-anchor" href="#输入格式支持" aria-label="Permalink to &quot;输入格式支持&quot;">​</a></h4><p>输入区支持标准的 Markdown 语法，以及以下扩展格式：</p><table tabindex="0"><thead><tr><th>格式</th><th>语法示例</th><th>说明</th></tr></thead><tbody><tr><td>标准 Markdown</td><td><code># 标题</code>、<code>**粗体**</code></td><td>标题、粗体、斜体、列表、链接、图片等</td></tr><tr><td>GFM 扩展</td><td><code>- [ ] 任务</code>、<code>| 表格 |</code></td><td>任务列表、表格、删除线</td></tr><tr><td>KaTeX 公式</td><td><code>$E=mc^2$</code>、<code>$$\\sum_{i=1}^n$$</code></td><td>行内和块级数学公式</td></tr><tr><td>Mermaid 图表</td><td><code>```mermaid ...</code></td><td>流程图、时序图、甘特图等</td></tr><tr><td>HTML 混合</td><td><code>&lt;div style=&quot;...&quot;&gt;...&lt;/div&gt;</code></td><td>HTML 与 Markdown 深度嵌套</td></tr><tr><td>LLM 思考块</td><td><code>&lt;think&gt;...&lt;/think&gt;</code></td><td>可折叠的思考过程块</td></tr><tr><td>VCP 工具调用</td><td><code>&lt;&lt;&lt;[TOOL_REQUEST]&gt;&gt;&gt;</code></td><td>VCP 协议工具调用格式</td></tr></tbody></table><blockquote><p>TODO: 截图 - 输入区编辑器，标注代码编辑器顶部工具栏</p></blockquote><h3 id="预览区" tabindex="-1">预览区 <a class="header-anchor" href="#预览区" aria-label="Permalink to &quot;预览区&quot;">​</a></h3><p>预览区位于页面底部，实时展示输入内容的渲染结果。这是你在测试中主要关注的区域。</p><h4 id="渲染模式" tabindex="-1">渲染模式 <a class="header-anchor" href="#渲染模式" aria-label="Permalink to &quot;渲染模式&quot;">​</a></h4><p>预览区支持四种渲染器版本，通过右侧配置面板的 <strong>渲染器版本</strong> 下拉菜单切换：</p><table tabindex="0"><thead><tr><th>版本</th><th>标识</th><th>特点</th><th>推荐场景</th></tr></thead><tbody><tr><td>V1 - Markdown-it</td><td><code>v1-markdown-it</code></td><td>基于 markdown-it 的增量解析器</td><td>兼容性测试、性能对比</td></tr><tr><td>V2 - Custom Parser</td><td><code>v2-custom-parser</code></td><td><strong>推荐</strong>自研 AST 解析器，支持复杂 HTML 和 LLM 思考块</td><td>日常测试、新功能验证</td></tr><tr><td>Pure Markdown-it</td><td><code>pure-markdown-it</code></td><td>纯 markdown-it 无增量优化</td><td>基准测试</td></tr><tr><td>Hybrid V3</td><td><code>hybrid-v3</code></td><td>混合策略 V3 版本（规划中）</td><td>预留</td></tr></tbody></table><blockquote><p>TODO: 截图 - 同一内容在 V1 和 V2 下的渲染对比</p></blockquote><h4 id="可视化块状态" tabindex="-1">可视化块状态 <a class="header-anchor" href="#可视化块状态" aria-label="Permalink to &quot;可视化块状态&quot;">​</a></h4><p>在右侧 <strong>渲染配置</strong> 中开启 <strong>可视化块状态</strong> 开关后，预览区中的每个 AST 节点都会显示其状态标签：</p><ul><li><strong>🟢 stable</strong>：语法完整的稳定节点，不会再次变化</li><li><strong>🟡 pending</strong>：待定区的节点，可能随着新内容到达而改变</li></ul><p>这在调试流式渲染问题时特别有用，可以直观地看到哪些内容还在变化中。</p><blockquote><p>TODO: 截图 - 开启可视化块状态后的预览区，标注 stable 和 pending 标签</p></blockquote><h3 id="配置面板" tabindex="-1">配置面板 <a class="header-anchor" href="#配置面板" aria-label="Permalink to &quot;配置面板&quot;">​</a></h3><p>配置面板位于预览区右侧，是工具的核心控制区域，分为多个功能区块。</p><h4 id="渲染配置" tabindex="-1">渲染配置 <a class="header-anchor" href="#渲染配置" aria-label="Permalink to &quot;渲染配置&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>渲染器版本</td><td>选择渲染引擎</td><td>V2 - Custom Parser</td></tr><tr><td>节流时间 (ms)</td><td>AST 更新节流间隔，控制打字机更新频率</td><td>80ms</td></tr><tr><td>启用节流</td><td>是否启用 AST 更新节流</td><td>✅ 开启</td></tr><tr><td>启用流式平滑化</td><td>平滑 Token 发射节奏，避免视觉卡顿</td><td>✅ 开启</td></tr><tr><td>可视化块状态</td><td>显示稳定区/待定区状态标签</td><td>❌ 关闭</td></tr><tr><td>启用调试日志</td><td>输出详细渲染日志到控制台（会刷屏）</td><td>❌ 关闭</td></tr></tbody></table><blockquote><p>TODO: 截图 - 渲染配置区块</p></blockquote><h4 id="样式编辑器" tabindex="-1">样式编辑器 <a class="header-anchor" href="#样式编辑器" aria-label="Permalink to &quot;样式编辑器&quot;">​</a></h4><p>样式编辑器让你可以<strong>所见即所得</strong>地调整 Markdown 元素的 CSS 样式：</p><ul><li><strong>全局开关</strong>：控制是否应用任何自定义样式</li><li><strong>元素列表</strong>：段落、粗体、斜体、删除线、引用、块引用、警告块、行内代码、链接、H1-H6 标题</li><li><strong>每个元素可调整</strong>： <ul><li>颜色</li><li>背景色</li><li>字体粗细 / 斜体 / 装饰线</li><li>文字发光（text-shadow）</li><li>边框发光（box-shadow）</li><li>边框圆角</li></ul></li></ul><blockquote><p>TODO: 截图 - 样式编辑器面板，展示某个元素的编辑状态</p></blockquote><h4 id="llm-思考规则" tabindex="-1">LLM 思考规则 <a class="header-anchor" href="#llm-思考规则" aria-label="Permalink to &quot;LLM 思考规则&quot;">​</a></h4><p>用于配置哪些 XML 标签应被识别为&quot;思考节点&quot;。默认已包含两个规则：</p><table tabindex="0"><thead><tr><th>规则</th><th>标签名</th><th>显示名称</th><th>默认折叠</th></tr></thead><tbody><tr><td>standard-think</td><td><code>&lt;think&gt;</code></td><td>思考过程</td><td>✅ 折叠</td></tr><tr><td>gugu-think</td><td><code>&lt;guguthink&gt;</code></td><td>咕咕的思考</td><td>❌ 展开</td></tr></tbody></table><p>你可以：</p><ul><li><strong>添加新规则</strong>：指定标签名、显示名称和是否默认折叠</li><li><strong>编辑规则</strong>：修改现有规则的参数</li><li><strong>删除规则</strong>：移除不需要的规则</li><li><strong>重置为默认</strong>：一键恢复默认配置</li></ul><blockquote><p>TODO: 截图 - LLM 思考规则编辑器</p></blockquote><h4 id="安全配置" tabindex="-1">安全配置 <a class="header-anchor" href="#安全配置" aria-label="Permalink to &quot;安全配置&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>默认渲染 HTML</td><td>是否默认渲染 HTML 代码块</td><td>❌</td></tr><tr><td>HTML 无边框模式</td><td>HTML 预览无边框渲染</td><td>❌</td></tr><tr><td>CDN 本地化</td><td>自动替换 CDN 链接为本地资源</td><td>✅</td></tr><tr><td>允许危险 HTML</td><td>允许渲染 script/iframe 等标签</td><td>❌</td></tr><tr><td>启用进入动画</td><td>新增节点是否带淡入动画</td><td>✅</td></tr><tr><td>允许外部脚本</td><td>是否允许加载外部 CDN 脚本</td><td>❌</td></tr><tr><td>默认展开代码块</td><td>代码块默认展开</td><td>❌</td></tr><tr><td>默认折叠工具调用</td><td>工具调用默认折叠</td><td>❌</td></tr></tbody></table><blockquote><p>TODO: 截图 - 安全配置区块</p></blockquote><h4 id="流式配置" tabindex="-1">流式配置 <a class="header-anchor" href="#流式配置" aria-label="Permalink to &quot;流式配置&quot;">​</a></h4><p>当开启流式模式时，以下配置控制流式模拟的行为：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>流式速度</td><td>输出速度（字符/秒）</td><td>100</td></tr><tr><td>初始延迟</td><td>开始输出前的等待时间（ms）</td><td>500</td></tr><tr><td>启用波动</td><td>模拟真实网络环境下的发包抖动</td><td>❌</td></tr><tr><td>延迟波动</td><td>延迟的随机波动范围（min~max ms）</td><td>50~200</td></tr><tr><td>字符波动</td><td>单次输出字符数的随机波动范围</td><td>1~10</td></tr></tbody></table><blockquote><p>TODO: 截图 - 流式配置区块</p></blockquote><h3 id="测试报告" tabindex="-1">测试报告 <a class="header-anchor" href="#测试报告" aria-label="Permalink to &quot;测试报告&quot;">​</a></h3><p>测试报告功能让你可以将测试结果导出为结构化报告，用于问题复现和团队协作。</p><p>点击工具栏的 <strong>复制报告</strong> 按钮，会弹出一个配置对话框，让你选择报告包含的内容：</p><table tabindex="0"><thead><tr><th>报告内容</th><th>说明</th></tr></thead><tbody><tr><td>测试配置</td><td>包含渲染器版本、流式参数等配置信息</td></tr><tr><td>原文</td><td>输入的原始 Markdown 内容</td></tr><tr><td>渲染 HTML</td><td>渲染后的 HTML 代码</td></tr><tr><td>规范化原文</td><td>经过规范化处理后的原文</td></tr><tr><td>规范化渲染</td><td>规范化处理后的渲染结果</td></tr><tr><td>对比结果</td><td>原文与渲染结果的逐行对比</td></tr><tr><td>样式配置</td><td>当前的样式编辑器设置</td></tr></tbody></table><p>选择完成后点击复制，报告会以 JSON 格式复制到剪贴板。</p><blockquote><p>TODO: 截图 - 复制报告配置对话框</p></blockquote><h3 id="实时-ast-查看器" tabindex="-1">实时 AST 查看器 <a class="header-anchor" href="#实时-ast-查看器" aria-label="Permalink to &quot;实时 AST 查看器&quot;">​</a></h3><p>AST 查看器以树状结构实时展示当前内容的抽象语法树。每个节点显示：</p><ul><li>节点类型（如 <code>paragraph</code>、<code>heading</code>、<code>code_block</code>）</li><li>节点属性（如 heading 的 level、code_block 的 language）</li><li>子节点层级展开/折叠</li></ul><p>这是深入理解渲染引擎内部结构的最佳工具——你可以清楚地看到一段 Markdown 文本是如何被拆解成层级化的 AST 节点的。</p><blockquote><p>TODO: 截图 - AST 查看器的树状结构展示</p></blockquote><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="复杂场景组合测试" tabindex="-1">复杂场景组合测试 <a class="header-anchor" href="#复杂场景组合测试" aria-label="Permalink to &quot;复杂场景组合测试&quot;">​</a></h3><p>通过不同的预设组合和配置调整，你可以测试各种复杂的渲染场景：</p><p><strong>场景一：HTML 沙箱渲染测试</strong></p><ol><li>选择一个包含复杂 HTML 的预设，如 <strong>复杂渲染测试 (complex-rendering-test)</strong></li><li>确保渲染器版本为 <strong>V2 - Custom Parser</strong></li><li>开启 <strong>默认渲染 HTML</strong> 开关</li><li>观察 HTML 内容如何在沙箱中渲染，包括内部的 SVG、交互元素等</li></ol><p><strong>场景二：流式状态下思考块行为</strong></p><ol><li>选择 <strong>LLM 思考节点 (llm-think-nodes)</strong> 预设</li><li>开启流式模式并设置较慢的流式速度（如 50 chars/s）</li><li>观察思考块在流式过程中如何从&quot;思考中&quot;状态过渡到&quot;已完成&quot;状态</li><li>尝试修改思考规则，添加自定义标签名来测试新的思考块类型</li></ol><p><strong>场景三：样式效果对比</strong></p><ol><li>选择 <strong>基本测试 (basic)</strong> 预设</li><li>打开样式编辑器，为标题设置不同的颜色和文字发光效果</li><li>在 V1 和 V2 渲染器之间切换，观察样式是否在两种引擎下表现一致</li><li>调整 <code>--card-opacity</code> 相关的透明度值，验证动态主题的通透效果</li></ol><h3 id="正则规则预处理" tabindex="-1">正则规则预处理 <a class="header-anchor" href="#正则规则预处理" aria-label="Permalink to &quot;正则规则预处理&quot;">​</a></h3><p>如果你需要在渲染前对内容进行预处理转换，可以在 <strong>正则配置（Regex Config）</strong> 中设置自定义正则规则。规则会在内容进入渲染器之前执行，实现自动替换和格式转换。</p><blockquote><p>TODO: 截图 - 正则配置面板</p></blockquote><h3 id="测试对比与回归" tabindex="-1">测试对比与回归 <a class="header-anchor" href="#测试对比与回归" aria-label="Permalink to &quot;测试对比与回归&quot;">​</a></h3><p>当你修改了渲染引擎的代码后，可以使用这个工具进行回归测试：</p><ol><li>逐个运行所有预设用例</li><li>使用 <strong>复制报告</strong> 功能保存当前版本的渲染结果作为基线</li><li>修改代码后重新测试，对比报告差异</li><li>确认所有预设的渲染效果均符合预期</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-v1-和-v2-渲染器有什么区别-我应该用哪个" tabindex="-1">Q：V1 和 V2 渲染器有什么区别？我应该用哪个？ <a class="header-anchor" href="#q-v1-和-v2-渲染器有什么区别-我应该用哪个" aria-label="Permalink to &quot;Q：V1 和 V2 渲染器有什么区别？我应该用哪个？&quot;">​</a></h3><p>V1（Markdown-it）是行业标准的 Markdown 解析器，兼容性好但功能有限——不支持 LLM 思考块、VCP 工具调用和复杂 HTML 嵌套。V2（Custom Parser）是自研的 AST 解析器，在这些 LLM 特定场景下有更好的表现。<strong>日常测试推荐使用 V2</strong>，在遇到兼容性问题时可以切换到 V1 做对比验证。</p><h3 id="q-为什么我的-html-内容没有渲染" tabindex="-1">Q：为什么我的 HTML 内容没有渲染？ <a class="header-anchor" href="#q-为什么我的-html-内容没有渲染" aria-label="Permalink to &quot;Q：为什么我的 HTML 内容没有渲染？&quot;">​</a></h3><p>请检查以下配置：</p><ol><li>是否开启了 <strong>默认渲染 HTML</strong> 开关（默认关闭）</li><li>如果使用了 <code>script</code>、<code>iframe</code> 等标签，需要开启 <strong>允许危险 HTML</strong></li><li>如果引用了外部 CDN 资源，确保 <strong>允许外部脚本</strong> 已开启</li><li>如果是裸 HTML 页面（以 <code>&lt;!DOCTYPE html&gt;</code> 开头），引擎会自动包裹在代码块中，防止 UI 爆破</li></ol><h3 id="q-流式模拟时页面卡顿怎么办" tabindex="-1">Q：流式模拟时页面卡顿怎么办？ <a class="header-anchor" href="#q-流式模拟时页面卡顿怎么办" aria-label="Permalink to &quot;Q：流式模拟时页面卡顿怎么办？&quot;">​</a></h3><p>可以尝试以下优化：</p><ol><li>降低 <strong>流式速度</strong>（减少字符/秒）</li><li>增加 <strong>节流时间</strong>（如从 80ms 调整到 150ms）</li><li>关闭 <strong>启用流式平滑化</strong>（减少缓冲层开销）</li><li>关闭 <strong>启用进入动画</strong>（减少动画渲染压力）</li><li>如果仍然卡顿，可以切换到 <strong>Pure Markdown-it</strong> 模式做基准对比</li></ol><h3 id="q-如何测试一个自定义的-llm-思考块标签" tabindex="-1">Q：如何测试一个自定义的 LLM 思考块标签？ <a class="header-anchor" href="#q-如何测试一个自定义的-llm-思考块标签" aria-label="Permalink to &quot;Q：如何测试一个自定义的 LLM 思考块标签？&quot;">​</a></h3><p>在右侧配置面板的 <strong>LLM 思考规则</strong> 区域，点击 <strong>添加规则</strong>：</p><ol><li><strong>规则 ID</strong>：输入唯一标识（如 <code>my-custom-think</code>）</li><li><strong>标签名</strong>：输入自定义 XML 标签名（如 <code>mythink</code>——<strong>不要包含尖括号</strong>）</li><li><strong>显示名称</strong>：输入 UI 显示名称（如 &quot;我的思考&quot;）</li><li><strong>默认折叠</strong>：选择是否默认折叠</li><li>保存后在输入区使用 <code>&lt;mythink&gt;...内容...&lt;/mythink&gt;</code> 即可看到效果</li></ol><h3 id="q-样式编辑器中调整后没有变化" tabindex="-1">Q：样式编辑器中调整后没有变化？ <a class="header-anchor" href="#q-样式编辑器中调整后没有变化" aria-label="Permalink to &quot;Q：样式编辑器中调整后没有变化？&quot;">​</a></h3><p>可能的原因：</p><ol><li>检查 <strong>全局开关</strong> 是否已开启（在样式编辑器顶部）</li><li>检查对应元素的 <strong>启用</strong> 开关是否已开启</li><li>尝试切换一次渲染器版本，强制刷新样式绑定</li><li>自定义样式只在 <strong>V1</strong> 和 <strong>V2</strong> 渲染器中生效，Pure Markdown-it 模式下不会应用</li></ol><h3 id="q-如何将测试结果分享给团队" tabindex="-1">Q：如何将测试结果分享给团队？ <a class="header-anchor" href="#q-如何将测试结果分享给团队" aria-label="Permalink to &quot;Q：如何将测试结果分享给团队？&quot;">​</a></h3><p>使用 <strong>复制报告</strong> 功能：</p><ol><li>点击工具栏的 <strong>复制报告</strong> 按钮</li><li>在配置对话框中选择需要包含的内容</li><li>点击复制，报告以 JSON 格式存入剪贴板</li><li>将 JSON 内容粘贴到文档、Issue 或聊天中</li><li>报告包含完整的测试配置、原文、渲染结果和对比信息，团队成员可以据此复现问题</li></ol>',110)])])}const b=o(e,[["render",l]]);export{u as __pageData,b as default};
